import { styled } from 'styled-components';

import { Icon } from '#components/Icon';

import * as device from '#theme/devices';

export const Wrapper = styled.div`
  --touch-area: 44px;
  --button-width: 12px;
  --arrow-width: 12px;
  --tooltip-width: 239px;
  --tooltip-offset-fallback: 30px;

  @media ${device.mobileM} {
    --button-width: 16px;
  }

  display: block;
  position: relative;
  width: var(--button-width);
  height: var(--button-width);
  cursor: help;
`;

export const TooltipButton = styled.button`
  /* add the padding to increase the touch area and then use negative margins to reduce the effect */
  --padding: calc((var(--touch-area) - var(--button-width)) / 2);
  display: block;
  position: absolute;
  width: var(--touch-area);
  height: var(--touch-area);
  box-sizing: border-box;
  padding: var(--padding);
  margin: calc(var(--padding) * -1);
  border: 0;
  cursor: inherit;
  line-height: var(--button-width);
`;

interface TooltipBodyProps {
  $isOpen?: boolean;
}

export const TooltipBody = styled.span.attrs({
  role: 'tooltip',
})<TooltipBodyProps>`
  /* position directly below and outside of the button and then give room for the arrow */
  --tooltip-top: calc(100% + var(--arrow-width) - (var(--button-width) / 2));

  /* calculate position of the tooltip if there were no constraints e.g. directly beneath centrally-aligned */
  --tooltip-offset-natural: calc(
    (var(--tooltip-width) - var(--button-width)) / 2
  );

  /* pick up the variable set in the JS explaing the left hand boundary, default to something safe */
  --tooltip-offset-max: var(--bounds-left, var(--tooltip-offset-fallback));

  /* choose whichever is not going to cause overflow */
  --tooltip-offset: calc(
    min(var(--tooltip-offset-natural), var(--tooltip-offset-max))
  );

  /* position the arrow based on the derived tooltip position */
  --arrow-left: calc(
    var(--arrow-width) - (var(--button-width) / 2) - var(--tooltip-offset)
  );

  --tooltip-color: ${({ theme }) => theme.color.canvas.card};
  position: absolute;
  top: var(--tooltip-top);
  left: calc(var(--tooltip-offset) * -1);
  width: 50vw;
  max-width: var(--tooltip-width);
  box-sizing: border-box;
  padding: ${({ theme }) => theme.spacing.x1}px;
  border-radius: 6px;
  background-color: var(--tooltip-color);
  box-shadow: 1px 2px 4px 0px ${({ theme }) => theme.color.veil.base};
  font: ${({ theme }) => theme.textStyle.tooltip.base};
  visibility: ${({ $isOpen }) => ($isOpen ? 'visible' : 'hidden')};

  &::after {
    display: block;
    position: absolute;
    bottom: 100%;
    left: calc(var(--arrow-left) * -1);
    width: 0;
    height: 0;
    box-sizing: content-box;
    border: var(--arrow-width) solid transparent;
    border-bottom-color: var(--tooltip-color);
    content: '';
  }

  ${TooltipButton}:focus-visible ~ & {
    visibility: visible;
  }
`;

export const StyledIcon = styled(Icon)`
  --width: var(--button-width);
`;
