import { forwardRef } from 'react';

import {
  StyledIcon,
  TooltipButton,
  Wrapper,
  TooltipBody,
} from './Tooltip.styles';
import { TooltipProps, TooltipRefElement } from './Tooltip.types';

import infoSVG from '#icons/info-outline-16.svg';

const Tooltip = forwardRef<TooltipRefElement, TooltipProps>(function Tooltip(
  {
    children,
    id,
    buttonTitle = 'More info',
    icon = infoSVG,
    isOpen = false,
    onInteract,
    className,
    onFocus,
    buttonProps,
  },
  ref,
) {
  return (
    <Wrapper className={className} ref={ref} onClick={onInteract}>
      <TooltipButton
        aria-describedby={id}
        title={buttonTitle}
        onFocus={onFocus}
        {...buttonProps}
      >
        <StyledIcon svg={icon} />
      </TooltipButton>
      <TooltipBody id={id} $isOpen={isOpen}>
        {children}
      </TooltipBody>
    </Wrapper>
  );
});

export default Tooltip;
