import { forwardRef, useRef } from 'react';

import Tooltip from './Tooltip';
import { useClickOutside } from './Tooltip.hooks';
import {
  TooltipRefElement,
  WithRepositioningAndOutsideClosingProps,
} from './Tooltip.types';

const TooltipWithClickOutsideClosing = forwardRef<
  TooltipRefElement,
  WithRepositioningAndOutsideClosingProps
>(function TooltipWithClickOutsideClosing({ onOutsideClick, ...rest }, ref) {
  const tooltipRef = ref || useRef<TooltipRefElement>(null);
  useClickOutside(tooltipRef, onOutsideClick);

  return <Tooltip {...rest} ref={tooltipRef} />;
});

export default TooltipWithClickOutsideClosing;
