import React, { useRef } from 'react';

import { useClickOutside } from './Tooltip.hooks';
import {
  TooltipRefElement,
  WithRepositioningAndOutsideClosingProps,
} from './Tooltip.types';
import TooltipWithRepositioning from './TooltipWithRepositioning';

const TooltipWithRepositioningAndOutsideClosing: React.FC<
  WithRepositioningAndOutsideClosingProps
> = ({ onOutsideClick, ...rest }) => {
  const tooltipRef = useRef<TooltipRefElement>(null);
  useClickOutside(tooltipRef, onOutsideClick);
  return <TooltipWithRepositioning {...rest} ref={tooltipRef} />;
};

export default TooltipWithRepositioningAndOutsideClosing;
