import React, { useState } from 'react';

import Tooltip from './Tooltip';
import { TooltipStatefulProps } from './Tooltip.types';

const TooltipStateful: React.FC<TooltipStatefulProps> = ({
  defaultOpen = false,
  ...props
}) => {
  const [isOpen, setIsOpen] = useState(defaultOpen);
  const onInteract = () => setIsOpen((isOpen) => !isOpen);
  return <Tooltip {...props} isOpen={isOpen} onInteract={onInteract} />;
};

export default TooltipStateful;
