import { forwardRef, useEffect, useRef } from 'react';

import Tooltip from './Tooltip';
import { TooltipProps, TooltipRefElement } from './Tooltip.types';

type tooltipElement = TooltipRefElement | null;

// updates the tooltip's left hand position on resize
const TooltipWithRepositioning = forwardRef<TooltipRefElement, TooltipProps>(
  function TooltipWithRepositioning(props, ref) {
    const tooltipRef = ref || useRef<TooltipRefElement>(null);

    useEffect(() => {
      const tooltipElement: tooltipElement =
        tooltipRef && typeof tooltipRef === 'object'
          ? tooltipRef.current
          : null;
      const init = (tooltip: tooltipElement) => {
        const rect = tooltip?.getBoundingClientRect();
        if (rect) {
          tooltip?.setAttribute(
            'style',
            `--bounds-left: ${Math.ceil(rect.left)}px`,
          );
        }
      };
      const resizeEventHandler = () => init(tooltipElement);

      window.addEventListener('resize', resizeEventHandler);
      init(tooltipElement);

      return () => {
        window.removeEventListener('resize', resizeEventHandler);
      };
    }, [tooltipRef]);

    return <Tooltip {...props} ref={tooltipRef} />;
  },
);

export default TooltipWithRepositioning;
