import React, { useRef, useEffect } from 'react';

import { CLASS_OUTSIDE_CLICK_EXCEPTION } from './Tooltip.constants';

export type EventCallback = (e: MouseEvent) => unknown;
export type ElRef =
  | ((instance: HTMLDivElement | null) => void)
  | React.MutableRefObject<HTMLDivElement | null>;

export const useClickOutside = (elRef: ElRef, callback: EventCallback) => {
  const callbackRef = useRef<typeof callback | null>(null);
  callbackRef.current = callback;

  useEffect(() => {
    const outsideClickExceptionRoots = [
      ...document.getElementsByClassName(CLASS_OUTSIDE_CLICK_EXCEPTION),
    ];
    const handleClickOutside = (e: MouseEvent) => {
      const eventTarget = e.target as Element;

      if (
        outsideClickExceptionRoots?.some((root) => root?.contains(eventTarget))
      ) {
        return;
      }

      if (typeof elRef === 'object' && !elRef?.current?.contains(eventTarget)) {
        callbackRef?.current?.(e);
      }
    };

    document.addEventListener('click', handleClickOutside, true);
    return () => {
      document.removeEventListener('click', handleClickOutside, true);
    };
  }, [elRef, callbackRef]);
};
